// Compliant: Clean control flow without unreachable code
func validateUser(user User) error {
    if user.Email == "" {
        return errors.New("email is required")
    }

    if user.Age < 0 {
        return errors.New("age cannot be negative")
    }

    fmt.Println("Validation complete")
    return nil
}

// Compliant: Proper loop control flow
func processItems(items []Item) {
    for _, item := range items {
        if item.IsValid() {
            processItem(item)
            fmt.Println("Processing next item")
            continue // or break, depending on intended behavior
        }

        if item.ShouldSkip() {
            log.Printf("Skipping item %s", item.Name)
            continue
        }

        handleInvalidItem(item)
    }
}

// Compliant: Error handling without unreachable code
func criticalOperation(data []byte) error {
    if len(data) == 0 {
        log.Println("Empty data received")
        return errors.New("empty data not allowed")
    }

    return process(data)
}

// Compliant: Proper switch case structure
func handleAction(action string) error {
    switch action {
    case "create":
        err := createResource()
        if err != nil {
            return err
        }
        log.Println("Resource created successfully")
        return nil
    case "delete":
        err := deleteResource()
        if err != nil {
            return err
        }
        fmt.Println("Resource deleted successfully")
        return nil
    default:
        return errors.New("unknown action")
    }
}

// Compliant: Worker with proper shutdown mechanism
func worker(ctx context.Context) {
    for {
        select {
        case <-ctx.Done():
            log.Println("Worker shutting down")
            return
        default:
            processWork()
        }
    }
}

// Compliant: Multiple return paths with all code reachable
func authenticateUser(username, password string) (*User, error) {
    if username == "" {
        log.Println("Empty username provided")
        return nil, errors.New("username is required")
    }

    if password == "" {
        log.Println("Empty password provided")
        return nil, errors.New("password is required")
    }

    user := findUser(username)
    if user == nil {
        log.Printf("User not found: %s", username)
        return nil, errors.New("user not found")
    }

    if !checkPassword(user, password) {
        log.Printf("Invalid password for user: %s", username)
        return nil, errors.New("invalid password")
    }

    log.Printf("User authenticated successfully: %s", username)
    return user, nil
}

